mapper.update:
    UPDATE ess_device
	SET deleted_yn = 'Y',
	    deleted_at = NOW(),
	    is_main = 'N'
    WHERE device_id = #{deviceId}
      AND member_id = #{memberId}

mapper.select:
select d.device_id as deviceId, d.member_id as memberId, d.group_id as groupId, d.device_name as deviceName, d.location, d.capacity_kw as capacityKw, d.device_type as deviceType, d.status, d.install_date as installDate, d.latitude, d.longitude, d.nx, d.ny, d.is_main as isMain, d.ess_capacity_kwh as essCapacityKwh, d.current_charge_kwh as currentChargeKwh, d.charge_efficiency as chargeEfficiency, d.discharge_efficiency as dischargeEfficiency, d.electricity_rate as electricityRate, g.group_name as groupName, m.soc, m.record_time as recordTime from ess_device d left join ess_device_group g on d.group_id = g.group_id left join monitoring m on m.device_id = d.device_id and m.record_time = ( select max(m2.record_time) from monitoring m2 where m2.device_id = d.device_id ) where d.member_id = #{memberId} and d.deleted_yn = 'N'
and d.group_id = #{groupId}
and d.device_id = #{deviceId}
order by d.is_main desc ,d.device_id desc

mapper.update:

update ess_device

   set is_main = 'Y'

 where member_id = #{memberId}
   and device_id = #{deviceId}
   and deleted_yn = 'N'

mapper.select:
select group_id
  from ess_device_group
 where member_id = #{memberId}
   and group_name = #{groupName}
